def path_fraction(distance, time):
    # Kiem tra hop le de tranh ZeroDivisionError truoc khi thuc hien tinh toan
    if time == 0:
        return 'Loi: Thoi gian khong the bang 0. Khong the tinh van toc.'

    try:
        velocity = distance / time
        return f'Van toc la: {velocity} m/s'
    except ZeroDivisionError:
        return 'Da xay ra loi: Chia cho so khong!'

print(path_fraction(100, 5))
print(path_fraction(100, 0))

