function processOrder(user, cart) {
  if (user !== null) {
    if (user.isActive) {
      if (cart.items.length > 0) {
        return "Order processed successfully";
      } else {
        return "Cart is empty";
      }
    } else {
      return "User is inactive";
    }
  } else {
    return "User not found";
  }
}

// SAU: Tái cấu trúc sạch sử dụng kỹ thuật Guard Clauses (Early Return)
function processOrderClean(user, cart) {
  if (!user) return "User not found";
  if (!user.isActive) return "User is inactive";
  if (cart.items.length === 0) return "Cart is empty";

  return "Order processed successfully";
}

