import os

# Giả lập danh sách thư viện phụ thuộc của dự án
dependencies = {
    "requests": "2.31.0",
    "numpy": "1.26.4"
}

# 1. Ghi thông tin thư viện ra file requirements.txt
def write_requirements(file_path="requirements.txt"):
    with open(file_path, "w", encoding="utf-8") as f:
        for pkg, ver in dependencies.items():
            f.write(f"{pkg}=={ver}\n")
    print(f"Đã xuất specs ra {file_path}")

# 2. Đọc và phân tích cú pháp tệp requirements.txt
def parse_requirements(file_path="requirements.txt"):
    if not os.path.exists(file_path):
         return []

    dependencies_list = []
    with open(file_path, "r", encoding="utf-8") as f:
        for line in f:
            cleaned_line = line.strip()
            if cleaned_line and not cleaned_line.startswith('#'):
                parts = cleaned_line.split('==')
                if len(parts) == 2:
                    dependencies_list.append({"library": parts[0], "version": parts[1]})
    return dependencies_list

if __name__ == '__main__':
    write_requirements()
    parsed = parse_requirements()
    print("Kết quả đọc file requirements.txt:", parsed)

