def evaluate_truthiness(items):
    """Kiểm tra và phân loại các giá trị Truthy/Falsy."""
    report = {}
    for item in items:
        is_truthy = bool(item)
        report[repr(item)] = "Truthy" if is_truthy else "Falsy"
    return report

def print_python_truth_table():
    """Sinh bảng chân trị chính xác theo cơ chế trả về giá trị thực của Python."""
    test_cases = [(0, 1), (False, True), ("", "Python")]
    results = []
    for x, y in test_cases:
        results.append({
            "x": repr(x),
            "y": repr(y),
            "x_and_y": repr(x and y),
            "x_or_y": repr(x or y),
            "not_x": repr(not x)
        })
    return results

