def safe_division_and_indexing(data_list, index, divisor):
    # Ứng dụng Short-circuit tránh lỗi IndexError và ZeroDivisionError
    # Nếu data_list None hoặc rỗng, len(data_list) sẽ ngắn mạch dừng lại
