def check_rbac_access_bad(user, action, resource):
    # Phức tạp, lồng nhau quá sâu, khó theo dõi và dễ sinh lỗi logic
    if user is not None:
        if user.get("is_active"):
            if user.get("role") == "admin":
                return True
            else:
                if resource is not None:
                    allowed_roles = resource.get("permissions", {}).get(action, [])
                    if user.get("role") in allowed_roles:
                        return True
                    else:
                        return False
                else:
                    return False
        else:
            return False
    else:
        return False

def check_rbac_access_refactored(user, action, resource):
    # Tái cấu trúc bằng Guard Clauses (Nhập sớm, thoát sớm - Clean & readable)
    if not user or not user.get("is_active"):
        return False

    if user.get("role") == "admin":
        return True

    if not resource or not action:
        return False

    allowed_roles = resource.get("permissions", {}).get(action, [])
    return user.get("role") in allowed_roles

def test_rbac_truth_table():
    # Automated Unit Test kiểm tra tính đúng đắn của bảng chân trị RBAC
    mock_resource = {"permissions": {"write": ["editor", "manager"], "delete": ["manager"]}}

    test_cases = [
        # (user, action, resource, expected_outcome)
        (None, "write", mock_resource, False), 
        ({"role": "editor", "is_active": False}, "write", mock_resource, False), 
        ({"role": "editor", "is_active": True}, "write", mock_resource, True), 
        ({"role": "editor", "is_active": True}, "delete", mock_resource, False), 
        ({"role": "admin", "is_active": True}, "delete", mock_resource, True),
        ({"role": "manager", "is_active": True}, "delete", mock_resource, True)
    ]

    for idx, (user, action, res, expected) in enumerate(test_cases):
        assert check_rbac_access_refactored(user, action, res) == expected, f"Failed at test {idx}"
    return "All RBAC test cases passed!"

