def analyze_and_reverse(data_str):
    # 1. Lọc dữ liệu ký tự số
    numeric_chars = []
    for char in data_str:
        if char.isdigit():
            numeric_chars.append(char)

    # 2. Tính toán tổng hợp
    total_sum = sum(int(num) for num in numeric_chars)

    # 3. Đảo ngược chuỗi ban đầu sử dụng vòng lặp ngược
    reversed_str = ''
    for i in range(len(data_str) - 1, -1, -1):
        reversed_str += data_str[i]

    return {
        'filtered_digits': numeric_chars,
        'digit_sum': total_sum,
        'reversed_string': reversed_str
    }

result = analyze_and_reverse('AI-2024-Coding')
print(result)

