    # Dùng continue lọc nhanh dữ liệu rác (chuỗi rỗng, giá trị chia cho 0) trước khi tính toán
    valid_averages = []
    for item in readings:
        if item is None or item.get("value") is None:
            continue  # Bỏ qua dữ liệu thiếu
        val = item["value"]
        divisor = item.get("divisor", 1)
        if divisor == 0:
