def execute_transaction_pipeline(data_chunks):
    # Thực thi tuần tự, commit khi toàn bộ chunk hợp lệ.
    # Nếu có bất kỳ chunk nào lỗi (invalid), rollback toàn bộ.
    for chunk in data_chunks:
        if not chunk.get("is_valid"):
            print(f"Phát hiện chunk lỗi ID {chunk.get('id')}. Hủy bỏ giao dịch.")
            break
    else:
        print("Tập dữ liệu hoàn hảo. Tiến hành commit tất cả các thay đổi vào database.")
        return True
    return False

