def calculate_efficiency(log: StudySessionLog) -> Dict[str, Any]:
    actual_total = log.actual_reading_minutes + log.actual_video_minutes + log.actual_quiz_minutes
    variance = actual_total - log.estimated_load_minutes
    efficiency_status = "On Track"
    if variance > 15:
        efficiency_status = "Slowing Down - Needs adjustment"
    elif variance < -15:
        efficiency_status = "Fast Pace - Verify deep understanding"
    return {
