from typing import Dict, Any

class ProductPayload(BaseModel):
    name: str
    price: float
    quantity: int

def process_request_flow(raw_request_body: Dict[str, Any]) -> Dict[str, Any]:
    # Step 1: Input Validation and Serialization via Pydantic model
    try:
        validated_data = ProductPayload(**raw_request_body)
    except ValidationError as e:
        return {"status": "error", "errors": e.errors()}

    # Step 2: Convert Validated Object to dictionary payload for DB Layer
    db_payload = validated_data.model_dump()

    # Step 3: Simulate SQLAlchemy DB Entry operation
    db_payload["id"] = 101 # Simulated DB Identity Column Auto-increment

    # Step 4: Final Serialization and return Response
    return {"status": "success", "data": db_payload}

