from typing import List, Dict, Any

app = FastAPI(title="Roadmap Optimization Service")

class SchedulerService:
    def distribute_lessons(self, lessons: List[Dict[str, Any]], max_daily_minutes: int) -> List[Dict[str, Any]]:
        schedule = []
        current_day = 1
        current_day_minutes = 0
        current_day_lessons = []

        for lesson in lessons:
            load = lesson["cognitive_load_minutes"]
            lesson_total = load["html_reading"] + load["video_lecture"] + load["quiz_practice"]

            if current_day_minutes + lesson_total <= max_daily_minutes:
                current_day_lessons.append({"topic": lesson["topic"], "duration": lesson_total})
                current_day_minutes += lesson_total
            else:
                if current_day_lessons:
                    schedule.append({"day": current_day, "lessons": current_day_lessons, "total_minutes": current_day_minutes})
                current_day_lessons = [{"topic": lesson["topic"], "duration": lesson_total}]
                current_day_minutes = lesson_total
                current_day += 1

        if current_day_lessons:
            schedule.append({"day": current_day, "lessons": current_day_lessons, "total_minutes": current_day_minutes})
        return schedule

def get_scheduler_service() -> SchedulerService:
    return SchedulerService()

class OptimizeRequestBody(BaseModel):
    max_daily_minutes: int
    lessons: List[Dict[str, Any]]

@app.post("/api/v1/scheduler/optimize", status_code=status.HTTP_200_OK)
async def optimize_schedule(payload: OptimizeRequestBody, scheduler: SchedulerService = Depends(get_scheduler_service)):
    optimized_schedule = scheduler.distribute_lessons(payload.lessons, payload.max_daily_minutes)
    return {
        "message": "Schedule generated successfully",
        "schedule": optimized_schedule
    }

