class UserRepository:
    def __init__(self):
        self.db = []  # Simulated database
        self.counter = 1

    def get_all(self):
        return self.db

    def get_by_email(self, email: str):
        return next((u for u in self.db if u["email"] == email), None)

    def create(self, user_in: UserCreate):
        user_data = user_in.model_dump()
        user_data["id"] = self.counter
        user_data["is_active"] = True
        self.db.append(user_data)
        self.counter += 1
        return user_data

