import logging
import time
from fastapi import FastAPI, Request
from fastapi.responses import JSONResponse
from starlette.middleware.base import BaseHTTPMiddleware

logging.basicConfig(level=logging.INFO, format="%(asctime)s - %(levelname)s - %(message)s")
logger = logging.getLogger(__name__)

app = FastAPI(title="Hệ thống Gỡ lỗi và Giám sát API")

class VerificationError(Exception):
    def __init__(self, detail: str):
        self.detail = detail

@app.exception_handler(VerificationError)
async def verification_error_handler(request: Request, exc: VerificationError):
    logger.error(f"Lỗi xác thực xảy ra tại: {request.url.path} - Chi tiết: {exc.detail}")
    return JSONResponse(
        status_code=400,
        content={"success": False, "error": "Verification Error", "detail": exc.detail}
    )

class DebuggingMiddleware(BaseHTTPMiddleware):
    async def dispatch(self, request: Request, call_next):
        start_time = time.time()
        logger.info(f"Nhận HTTP Request: {request.method} {request.url.path}")
        try:
            response = await call_next(request)
            process_time = time.time() - start_time
            logger.info(f"Hoàn thành xử lý trong {process_time:.4f}s với Code: {response.status_code}")
            return response
        except Exception as e:
            logger.exception(f"Lỗi hệ thống chưa được xử lý: {str(e)}")
            return JSONResponse(status_code=500, content={"detail": "Internal server error."})

app.add_middleware(DebuggingMiddleware)

@app.get("/trigger-error/")
def trigger_error():
    raise VerificationError("Học viên chưa hoàn thành bài tập thực hành tối thiểu (Quiz practice).")

