from fastapi import FastAPI, Depends, HTTPException, status
from pydantic import BaseModel
from typing import List, Dict

app = FastAPI(title="3-Tier Architecture Demonstration")

# -----------------------------------------------------
# 1. DATA LAYER (Mô phỏng truy xuất nguồn dữ liệu)
# -----------------------------------------------------
class MockDatabase:
    def __init__(self):
        self._data: Dict[int, dict] = {}
        self._counter = 1

    async def save(self, name: str, quantity: int) -> dict:
        record = {"id": self._counter, "name": name, "quantity": quantity}
        self._data[self._counter] = record
        self._counter += 1
        return record

    async def fetch_all(self) -> List[dict]:
        return list(self._data.values())

# Khởi tạo instance kết nối DB dùng chung (Singleton pattern)
db_connection = MockDatabase()

def get_database_connection() -> MockDatabase:
    return db_connection

# -----------------------------------------------------
# 2. BUSINESS LOGIC/SERVICE LAYER (Nghiệp vụ ứng dụng)
# -----------------------------------------------------
class ProductCreate(BaseModel):
    name: str
    quantity: int

class Product(ProductCreate):
    id: int

class ProductService:
    def __init__(self, db: MockDatabase):
        self.db = db

    async def retrieve_products(self) -> List[Product]:
        # Tách biệt lớp: Request thô đi từ DB lên logic chế biến định dạng
        records = await self.db.fetch_all()
        return [Product(**r) for r in records]

    async def register_product(self, product_in: ProductCreate) -> Product:
        # Nghiệp vụ: Số lượng tối thiểu của hàng hóa mới tạo phải > 0
        if product_in.quantity <= 0:
            raise ValueError("Số lượng đăng ký tồn kho phải lớn hơn 0.")
        raw_data = await self.db.save(product_in.name, product_in.quantity)
        return Product(**raw_data)

# Dependency Injection để sinh ra Service Layer tự động
def get_product_service(db: MockDatabase = Depends(get_database_connection)) -> ProductService:
    return ProductService(db)

# -----------------------------------------------------
# 3. PRESENTATION/API LAYER (Điểm tiếp nhận yêu cầu Client)
# -----------------------------------------------------
@app.get("/products", response_model=List[Product])
async def list_products(service: ProductService = Depends(get_product_service)):
    """Client gọi lên API layer -> API chuyển tiếp xuống Service Layer -> DB Layer"""
    return await service.retrieve_products()

@app.post("/products", response_model=Product, status_code=status.HTTP_201_CREATED)
async def create_product(
    product_in: ProductCreate, 
    service: ProductService = Depends(get_product_service)
):
    try:
        return await service.register_product(product_in)
    except ValueError as val_err:
        raise HTTPException(
            status_code=status.HTTP_400_BAD_REQUEST, 
            detail=str(val_err)
        )

