from fastapi import FastAPI, Depends, HTTPException, status
from pydantic import BaseModel
from typing import Generator, List, Dict, Any

app = FastAPI(title="Multi-tier Data Flow Integration")

# --- DATABASE SIMULATION LAYER (Data Tier) ---
class DatabaseConnection:
    def __init__(self):
        # In-memory mock database store
        self._db: List[Dict[str, Any]] = [
            {"id": 1, "name": "PostgreSQL Database Setup"},
            {"id": 2, "name": "FastAPI Quickstart Manual"}
        ]

    def fetch_all_items(self) -> List[Dict[str, Any]]:
        return self._db

    def insert_item(self, item: Dict[str, Any]) -> None:
        self._db.append(item)

# Global database instance representation
db_instance = DatabaseConnection()

# Dependency Injection function to yield Database connection
def get_db_connection() -> Generator[DatabaseConnection, None, None]:
    # Initiates session simulation
    db_conn = db_instance
    try:
        yield db_conn
    finally:
        # Connection closing process simulated here
        pass

# --- APPLICATION LAYER (API Tier Validation) ---
class ItemPayload(BaseModel):
    id: int
    name: str

# --- ENDPOINTS LAYER (Client to API communication) ---
@app.get("/api/v1/items", response_model=List[ItemPayload])
async def read_items(db: DatabaseConnection = Depends(get_db_connection)):
    # API Tier queries Data Tier and answers Client Tier
    return db.fetch_all_items()

@app.post("/api/v1/items", status_code=status.HTTP_201_CREATED)
async def create_item(
    payload: ItemPayload, 
    db: DatabaseConnection = Depends(get_db_connection)
):
    # Validate uniqueness simulating constraints checking
    existing_items = db.fetch_all_items()
    if any(item["id"] == payload.id for item in existing_items):
        raise HTTPException(
            status_code=status.HTTP_400_BAD_REQUEST, 
            detail="Item with duplicate ID already exists."
        )

    # API processes and commits to simulated Database layer
    db.insert_item(payload.model_dump())
    return {"status": "committed_successfully", "added": payload}

