async def get_book_from_db(book_id: int):
    book = FAKE_DATABASE.get(book_id)
    if not book:
        raise HTTPException(
            status_code=status.HTTP_404_NOT_FOUND,
            detail=f"Book voi ID {book_id} khong ton tai trong DB"
        )
    return {"source": "DATABASE", "data": book}

