async def custom_http_exception_handler(request: Request, exc: StarletteHTTPException):
    if exc.status_code == 404:
        return JSONResponse(
            status_code=404,
            content={
                "error": "404 Not Found",
                "message": f"Đường dẫn '{request.url.path}' không có trên hệ thống hoặc cấu hình sai."
