class MockDatabase:
    def __init__(self):
        self._items: Dict[int, dict] = {}
        self._counter = 0

    def get_all(self) -> List[dict]:
        return list(self._items.values())

    def get_by_id(self, item_id: int) -> Optional[dict]:
        return self._items.get(item_id)

