    openapi_schema["info"]["x-logo"] = {
        "url": "https://fastapi.tiangolo.com/img/logo-margin/logo-teal.png"
    }

    # Định nghĩa cơ chế xác thực Security Schemes cho API tài liệu
    openapi_schema["components"]["securitySchemes"] = {
        "HeaderApiKey": {
