import asyncio
from fastapi import FastAPI, Depends, HTTPException, status
from pydantic import BaseModel

app = FastAPI()

# --- 1. DATA ACCESS LAYER (Database Simulation) ---
class DatabaseConnection:
    def __init__(self):
        self.mock_db = {
            101: {"id": 101, "username": "hoang_nam", "email": "nam@example.com"}
        }

    async def query_user_by_id(self, user_id: int) -> dict:
        # Gia lap do tre mang hoac truy van o cung (Non-blocking I/O)
        await asyncio.sleep(0.1)
        return self.mock_db.get(user_id)

# Dependency Injection cho Database Connection
def get_db():
    db = DatabaseConnection()
    try:
        yield db
    finally:
        pass

# --- 2. PRESENTATION/DTO LAYER (Schemas) ---
class UserResponse(BaseModel):
    id: int
    username: str
    email: str

# --- 3. APPLICATION/API LAYER (Business Logic) ---
@app.get("/users/{user_id}", response_model=UserResponse)
