from pydantic import BaseModel
from typing import Generator

app = FastAPI(title="Simulated 3-Tier Architecture API")

# ========================================== 
# 1. DATABASE LAYER (Data Source Simulation)
# ==========================================
class FakeDatabaseSession:
    def __init__(self):
        # Simulated in-memory database table
        self.inventory = {
            1: {"id": 1, "name": "Python Web Development Book", "price": 29.99},
            2: {"id": 2, "name": "FastAPI Advanced Course", "price": 49.99}
        }

    def query_item_by_id(self, item_id: int) -> dict | None:
        return self.inventory.get(item_id)

# Dependency injection setup for Database connections
def get_db_connection() -> Generator[FakeDatabaseSession, None, None]:
    db_session = FakeDatabaseSession()
    try:
        yield db_session
    finally:
        # Clean up database resources logic here
        pass

# ==========================================
# 2. PRESENTATION LAYER (Schemas)
# ==========================================
class ProductResponse(BaseModel):
    id: int
    name: str
    price: float

# ==========================================
# 3. BUSINESS LOGIC LAYER (Service Handler)
# ==========================================
def get_product_business_logic(product_id: int, db: FakeDatabaseSession) -> dict:
    product = db.query_item_by_id(product_id)
    if not product:
        raise HTTPException(
            status_code=status.HTTP_404_NOT_FOUND,
            detail=f"Product with ID {product_id} is not available."
        )
    return product

# ==========================================
# 4. VIEW/ROUTER LAYER (Client -> Endpoint)
# ==========================================
@app.get("/products/{product_id}", response_model=ProductResponse)
def read_product(product_id: int, db: FakeDatabaseSession = Depends(get_db_connection)):
    # Delegation pattern passing the context down through layers
    return get_product_business_logic(product_id, db)

