from fastapi import FastAPI, Depends, HTTPException, status
from pydantic import BaseModel, PositiveInt
from typing import List, Optional, Dict
import asyncio

app = FastAPI(title="Layered Architecture Example")

# --- 1. DOMAIN MODELS & SCHEMAS --- 
class Product(BaseModel):
    id: int
    name: str
    price: float
    stock: int

class ProductCreate(BaseModel):
    name: str
    price: float
    stock: int

# --- 2. REPOSITORY LAYER (Data access layer, simulates DB interaction) ---
class ProductRepository:
    def __init__(self):
        # In-memory database simulation
        self._db: Dict[int, dict] = {
            1: {"id": 1, "name": "Laptop Dell", "price": 1200.0, "stock": 10},
            2: {"id": 2, "name": "Mouse MX Master", "price": 100.0, "stock": 0}
        }

    async def get_by_id(self, product_id: int) -> Optional[dict]:
        await asyncio.sleep(0.05) # Simulate database latency
        return self._db.get(product_id)

    async def add_product(self, product_data: dict) -> dict:
        await asyncio.sleep(0.05)
        new_id = max(self._db.keys(), default=0) + 1
        product_data["id"] = new_id
        self._db[new_id] = product_data
        return product_data

# Singleton Dependency provider
repo_instance = ProductRepository()
def get_product_repo() -> ProductRepository:
    return repo_instance

# --- 3. SERVICE LAYER (Business logic validation rules) ---
class ProductService:
    def __init__(self, repo: ProductRepository = Depends(get_product_repo)):
        self.repo = repo

    async def get_available_product(self, product_id: int) -> dict:
        product = await self.repo.get_by_id(product_id)
        if not product:
            raise HTTPException(status_code=404, detail="Product not found")
        if product["stock"] <= 0:
            raise HTTPException(status_code=status.HTTP_400_BAD_REQUEST, detail="Product is out of stock")
        return product

    async def create_new_product(self, product_in: ProductCreate) -> dict:
        if product_in.price <= 0:
            raise HTTPException(status_code=400, detail="Price must be greater than zero")
        new_product = {
            "name": product_in.name,
            "price": product_in.price,
            "stock": product_in.stock
        }
        return await self.repo.add_product(new_product)

# --- 4. ROUTER/CONTROLLER LAYER (HTTP interface endpoints) ---
@app.get("/products/{product_id}", response_model=Product)
async def get_product(product_id: int, service: ProductService = Depends()):
    # Delegation pattern: Controller delegates parsing & validation to service
    return await service.get_available_product(product_id)

@app.post("/products", response_model=Product, status_code=status.HTTP_201_CREATED)
async def create_product(product: ProductCreate, service: ProductService = Depends()):
    return await service.create_new_product(product)

