# --- 3. SERVICE LAYER (Xử lý Business Logic) ---
class UserService:
    def __init__(self, repo: UserRepository = Depends(UserRepository)):
        self.repo = repo

    def get_user_profile(self, user_id: int) -> UserResponse:
        raw_user = self.repo.get_by_id(user_id)
        if not raw_user:
            raise ValueError("User does not exist")
        return UserResponse(**raw_user)

# --- 4. CONTROLLER / API LAYER ---
