import time
from fastapi import FastAPI

app = FastAPI()

# ĐIỂM NGHẼN (BAD): Sử dụng hàm nghẽn I/O đồng bộ trong hàm xử lý async def
# Mọi yêu cầu truy cập router này sẽ block Event Loop chính, khiến các request khác phải chờ đợi.
@app.get("/bottleneck")
async def blocking_endpoint():
    time.sleep(2)  # Giả lập tác vụ nghẽn I/O (Query DB đồng bộ, ghi file nặng)
    return {"status": "blocking_done"}

# GIẢI PHÁP TỐI ƯU (GOOD): Thay thế bằng Async IO để giải phóng Event Loop
@app.get("/optimized")
async def non_blocking_endpoint():
    await asyncio.sleep(2)  # Giải phóng quyền kiểm soát để xử lý request khác trong thời gian chờ
    return {"status": "optimized_non_blocking_done"}

# GIẢI PHÁP THỰC TẾ (NẾU BẮT BUỘC DÙNG THƯ VIỆN ĐỒNG BỘ):
# Nếu khai báo hàm xử lý là 'def' thay vì 'async def', FastAPI sẽ tự động chạy nó trên một ThreadPool riêng biệt.
@app.get("/safe-sync")
def safe_blocking_endpoint():
    time.sleep(2)  # Không làm nghẽn Event Loop chính vì chạy trên luồng khác
    return {"status": "safe_sync_done"}

