from fastapi import FastAPI, Depends, HTTPException, status
from typing import Generator
import asyncio

app = FastAPI(title="Client-API-Database Flow Demo")

# Gia lap lop ket noi Database (Database Connection Manager)
class DatabaseConnection:
    def __init__(self):
        self.connection_active = True
        print("[DB] Da khoi tao ket noi Database")

    def fetch_data(self, query_id: int):
        # Gia lap du lieu truy van tu database
        if query_id == 100:
            return {"id": 100, "name": "Data Layer", "details": "Connected via FastAPI Dependency Injection"}
        return None

    def close(self):
        self.connection_active = False
        print("[DB] Da giai phong va dong ket noi Database")

# Dependency Generator: Quan ly vong doi ket noi Database cho moi Request
def get_db_connection() -> Generator[DatabaseConnection, None, None]:
    db = DatabaseConnection()
    try:
        yield db  # Cung cap doi tuong connection cho endpoint thuc thi
    finally:
        db.close()  # Luon duoc goi de don dep tai nguyen sau khi gui Response ve cho Client

# Endpoint su dung Dependency Injection de lay database connection thuc hien luong du lieu Client - API - DB
@app.get("/api/v1/data/{data_id}")
async def get_data_flow(
    data_id: int,
    db: DatabaseConnection = Depends(get_db_connection)
):
    # Gia lap bat dong bo (Non-blocking I/O) khi cho doi ket qua tu DB
    await asyncio.sleep(0.05)

    result = db.fetch_data(data_id)
    if not result:
        raise HTTPException(
            status_code=status.HTTP_404_NOT_FOUND,
            detail=f"Khong tim thay du lieu voi ID {data_id} trong database"
        )
    return {
        "status": "success",
        "db_status_during_call": db.connection_active,
        "data": result
    }

