import socket
import sys

def check_port(host: str, port: int) -> bool:
    """
    Kiểm tra xem một cổng hiện tại đang rảnh hay đã bị chiếm quyền binding.
    Trả về True nếu cổng đã bị chiếm dùng, False nếu cổng còn trống.
    """
    with socket.socket(socket.AF_INET, socket.SOCK_STREAM) as s:
        try:
            s.bind((host, port))
            return False  # Cổng rảnh, bind thành công
        except socket.error:
            return True   # Cổng bị chiếm dụng (Address already in use)

if __name__ == "__main__":
    test_host = "127.0.0.1"
    test_port = 8000

    if check_port(test_host, test_port):
        print(f"[LỖI KHỞI ĐỘNG]: Port {test_port} đã bị chiếm dụng trên {test_host}.")
        print("Vui lòng tắt ứng dụng đang chiếm dụng port hoặc đổi sang port khác bằng CLI:")
        print(f"  uvicorn main:app --port {test_port + 1}")
    else:
        print(f"[OK]: Port {test_port} hoàn toàn trống. Bạn có thể chạy Uvicorn khởi động Server.")

