from fastapi import FastAPI, HTTPException, Path, Query
from pydantic import BaseModel
from typing import Optional

app = FastAPI(title="FastAPI Data Flow Setup")

# Schema dinh nghia kieu du lieu dau vao (Pydantic validation)
class Product(BaseModel):
    name: str
    price: float
    description: Optional[str] = None

# Gia lap CSDL trong bo nho (Mock Database)
fake_db = {
    1: {"name": "Ban phim co", "price": 1500000.0, "description": "Ban phim co switch Red"},
    2: {"name": "Chuot gaming", "price": 850000.0, "description": "Chuot gaming khong day DPI cao"}
}

@app.get("/products/{product_id}")
async def get_product_by_id(
    product_id: int = Path(..., description="ID cua san pham phai lon hon 0", gt=0)
):
    # Luong du lieu nhan Path Parameter tu client -> Tra cuu DB -> Check loi -> Tra ve ket qua JSON
    if product_id not in fake_db:
        raise HTTPException(status_code=404, detail="Khong tim thay san pham yeu cau")
    return {"status": "success", "data": fake_db[product_id]}

@app.post("/products/", status_code=201)
async def create_product(product: Product):
    # Nhan body request -> validate -> luu tru gia lap vao database -> return status thich hop
    new_id = max(fake_db.keys(), default=0) + 1
    fake_db[new_id] = product.model_dump()
    return {
        "status": "created",
        "item_id": new_id,
        "data": fake_db[new_id]
    }

