from fastapi import FastAPI, Path, Query, status, HTTPException
from pydantic import BaseModel

app = FastAPI()

class Item(BaseModel):
    name: str
    price: float

database = {}

@app.post("/items/", status_code=status.HTTP_201_CREATED, tags=["items"])
def create_item(item: Item):
    database[item.name] = item
    return {"status": "success", "data": item}

@app.get("/items/{item_name}", tags=["items"])
def read_item(
    item_name: str = Path(..., description="Tên của vật phẩm cần hiển thị thông tin"),
    q: str | None = Query(None, description="Từ khóa tìm kiếm bổ sung")
):
    if item_name not in database:
        raise HTTPException(status_code=404, detail="Không tìm thấy vật phẩm này")
    return {"item": database[item_name], "query": q}

@app.put("/items/{item_name}", tags=["items"])
def update_item(item_name: str, item: Item):
    if item_name not in database:
        raise HTTPException(status_code=404, detail="Vật phẩm cần cập nhật không tồn tại")
    database[item_name] = item
    return {"status": "updated", "data": item}

@app.delete("/items/{item_name}", tags=["items"])
def delete_item(item_name: str):
    if item_name not in database:
        raise HTTPException(status_code=404, detail="Vật phẩm cần xóa không tồn tại")
    del database[item_name]
    return {"message": f"Vật phẩm {item_name} đã bị xóa thành công."}

