from fastapi import FastAPI, HTTPException
from pydantic import BaseModel
from typing import List, Optional

app = FastAPI()

# Pydantic Model để tự động validate kiểu dữ liệu truyền vào từ Client
class Product(BaseModel):
    id: int
    name: str
    price: float
    description: Optional[str] = None

# Database giả lập lưu trữ tạm thời trong RAM
database_mock: List[Product] = []

@app.get('/products', response_model=List[Product])
async def get_products():
    return database_mock

@app.post('/products', response_model=Product, status_code=201)
async def create_product(product: Product):
    # Validation nghiệp vụ: Trùng ID
    for p in database_mock:
        if p.id == product.id:
            raise HTTPException(status_code=400, detail='Sản phẩm đã tồn tại với ID này.')
    database_mock.append(product)
    return product

@app.put('/products/{product_id}', response_model=Product)
async def update_product(product_id: int, updated_product: Product):
    for idx, p in enumerate(database_mock):
        if p.id == product_id:
            database_mock[idx] = updated_product
            return updated_product
    raise HTTPException(status_code=404, detail='Không tìm thấy sản phẩm cần cập nhật.')

@app.delete('/products/{product_id}', status_code=200)
async def delete_product(product_id: int):
    for idx, p in enumerate(database_mock):
        if p.id == product_id:
            database_mock.pop(idx)
            return {'message': f'Đã xóa sản phẩm {product_id} thành công.'}
    raise HTTPException(status_code=404, detail='Không tìm thấy sản phẩm cần xóa.')

