from fastapi import FastAPI, Depends, HTTPException
from pydantic import BaseModel, EmailStr
from typing import Generator

app = FastAPI(title="Client-FastAPI-Database Flow")

# Mocking Database connection interface
class MockDatabaseSession:
    def __init__(self):
        self.status = "Connected"

    def save_user(self, user_data: dict):
        return {"id": 101, **user_data}

# Dependency function to manage DB session lifecycle
def get_db_session() -> Generator[MockDatabaseSession, None, None]:
    db = MockDatabaseSession()
    try:
        yield db
    finally:
        # Clean up database resources or close connection here
        db.status = "Closed"

class UserRegisterSchema(BaseModel):
    username: str
    email: EmailStr

@app.post("/register", status_code=201)
async def register_user(user: UserRegisterSchema, db: MockDatabaseSession = Depends(get_db_session)):
    user_payload = {"username": user.username, "email": user.email}
    try:
        result = db.save_user(user_payload)
        return {
            "status": "Success",
            "database_status": db.status,
            "db_saved_data": result
        }
    except Exception as e:
        raise HTTPException(status_code=500, detail=f"Database operation failed: {str(e)}")

