from pydantic import BaseModel

app = FastAPI()
database = {}

class Product(BaseModel):
    name: str
    price: float

@app.post("/products/{product_id}")
def create_product(product_id: int, product: Product):
    if product_id in database:
        raise HTTPException(status_code=400, detail="Sản phẩm đã tồn tại")
    database[product_id] = product.dict()
    return {"status": "success", "data": database[product_id]}

@app.get("/products/{product_id}")
def read_product(product_id: int):
    if product_id not in database:
        raise HTTPException(status_code=404, detail="Không tìm thấy sản phẩm")
    return database[product_id]

@app.put("/products/{product_id}")
def update_product(product_id: int, product: Product):
    if product_id not in database:
        raise HTTPException(status_code=404, detail="Không tìm thấy sản phẩm")
    database[product_id] = product.dict()
    return {"status": "updated", "data": database[product_id]}

@app.delete("/products/{product_id}")
def delete_product(product_id: int):
    if product_id not in database:
        raise HTTPException(status_code=404, detail="Không tìm thấy sản phẩm")
    del database[product_id]
    return {"status": "deleted"}

