from fastapi import FastAPI, HTTPException
from pydantic import BaseModel

app = FastAPI()

# Gia lap co so du lieu bang danh sach trong bo nho (In-memory list)
todo_db = [
    {"id": 1, "task": "Tim hieu mo hinh Client-Server"},
    {"id": 2, "task": "Thuc hanh HTTP request va response"}
]

# Dinh nghia schema du lieu dau vao su dung Pydantic
class TodoItem(BaseModel):
    task: str

# GET: Lay toan bo danh sach viec can lam
@app.get("/todos")
def get_all_todos():
    return todo_db

# POST: Them moi mot viec can lam (Tra ve status 201 Created dung chuan)
@app.post("/todos", status_code=201)
def create_todo(item: TodoItem):
    new_id = len(todo_db) + 1
    new_item = {"id": new_id, "task": item.task}
    todo_db.append(new_item)
    return new_item

# PUT: Cap nhat noi dung viec can lam theo ID
@app.put("/todos/{todo_id}")
def update_todo(todo_id: int, item: TodoItem):
    for idx, todo in enumerate(todo_db):
        if todo["id"] == todo_id:
            todo_db[idx]["task"] = item.task
            return todo_db[idx]
    raise HTTPException(status_code=404, detail="Khong tim thay task tuong ung de cap nhat")

# DELETE: Xoa mot viec can lam khoi he thong
@app.delete("/todos/{todo_id}")
def delete_todo(todo_id: int):
    for idx, todo in enumerate(todo_db):
        if todo["id"] == todo_id:
            deleted_todo = todo_db.pop(idx)
            return {"message": f"Da xoa thanh cong task co ID {todo_id}", "deleted_item": deleted_todo}
    raise HTTPException(status_code=404, detail="Khong tim thay task tuong ung de xoa")

