from fastapi import FastAPI, HTTPException
from pydantic import BaseModel

app = FastAPI(title="Kiểm thử Quy trình API")

# Cơ sở dữ liệu tạm thời lưu trữ trong bộ nhớ
db_items = {}

class Item(BaseModel):
    name: str
    price: float

@app.post("/items/{item_id}", status_code=201, tags=["Quy trình Sản phẩm"])
def create_item(item_id: int, item: Item):
    if item_id in db_items:
        raise HTTPException(status_code=400, detail="Mã sản phẩm này đã tồn tại")
    db_items[item_id] = item
    return {"status": "Tạo thành công", "item": item}

@app.get("/items/{item_id}", tags=["Quy trình Sản phẩm"])
def read_item(item_id: int):
    if item_id not in db_items:
        raise HTTPException(status_code=404, detail="Không tìm thấy sản phẩm yêu cầu")
    return db_items[item_id]

