from fastapi import FastAPI
from pydantic import BaseModel
from typing import List

app = FastAPI()

class LessonStatus(BaseModel):
    lesson_num: int
    topic: str
    is_completed: bool

@app.post("/study-plan/evaluate")
def evaluate_study_plan(lessons: List[LessonStatus]):
    total_lessons = len(lessons)
    if total_lessons == 0:
        return {"completed_ratio": 0, "status": "Empty plan"}

    completed_lessons = sum(1 for lesson in lessons if lesson.is_completed)
    completion_rate = completed_lessons / total_lessons

    return {
        "total_lessons": total_lessons,
        "completed_lessons": completed_lessons,
        "completion_rate": round(completion_rate * 100, 2),
        "status": "Hoan thanh tot" if completion_rate >= 0.8 else "Can co gang them"
    }

