from fastapi import FastAPI
from pydantic import BaseModel
from typing import Optional

app = FastAPI(
    title="API Kiểm Thử Swagger",
    description="API thực hành kiểm thử các phương thức HTTP và tham số trên Swagger UI.",
    version="1.0.0"
)

# Lớp mô tả cấu trúc dữ liệu gửi lên (Request Body)
class Book(BaseModel):
    title: str
    author: str
    pages: int

# Cơ sở dữ liệu tạm thời bằng Dictionary
books_db = {}

# 1. GET với Query Parameter (Lọc dữ liệu)
@app.get("/books")
def get_books(author: Optional[str] = None):
    if author:
        filtered_books = {k: v for k, v in books_db.items() if v["author"].lower() == author.lower()}
        return filtered_books
    return books_db

# 2. GET với Path Parameter (Lấy chi tiết)
@app.get("/books/{book_id}")
def get_book(book_id: int):
    if book_id in books_db:
        return books_db[book_id]
    return {"error": "Không tìm thấy sách"}

# 3. POST với Request Body (Thêm mới)
@app.post("/books/{book_id}")
def create_book(book_id: int, book: Book):
    books_db[book_id] = book.dict()
    return {"message": "Thêm sách thành công", "book": books_db[book_id]}

# 4. PUT với Request Body (Cập nhật toàn bộ)
@app.put("/books/{book_id}")
def update_book(book_id: int, book: Book):
    if book_id in books_db:
        books_db[book_id] = book.dict()
        return {"message": "Cập nhật thành công", "book": books_db[book_id]}
    return {"error": "Không tìm thấy sách để cập nhật"}

# 5. DELETE với Path Parameter (Xóa bỏ)
@app.delete("/books/{book_id}")
def delete_book(book_id: int):
    if book_id in books_db:
        deleted_book = books_db.pop(book_id)
        return {"message": "Xóa sách thành công", "deleted_book": deleted_book}
    return {"error": "Không tìm thấy sách để xóa"}

